    * @param spec Path specification.
    <PLACEHOLDER>
  static for (spec: string, version: '1' | '1.0' | '1.1' = '1.1'): Matcher {
    return new Matcher(spec, version)
  }
}

function compile (spec: string): {
  regex: string
  props: string[]
} {
  const parts: string[] = []
  const props: string[] = []
  let min = 0
  let max = 0
  let any = false
  let opt = true
  function flatten (final: boolean = false): void {
    if (max > 0 || any) {
      if (final && opt && min < 1) {
        min = 1
      } else if (min > 0) {
        opt = false
      }
      parts.push(any
        ? min < 2
          ? min < 1
            ? '(?:/[^/]+)*'
            : '(?:/[^/]+)+'
          : `(?:/[^/]+){${min},}`
        : max === 1
          ? min === 1
            ? '/[^/]+'
            : '(?:/[^/]+)?'
          : min === max
            ? `(?:/[^/]+){${min}}`
            : `(?:/[^/]+){${min},${max}}`)
    }
    min = 0
    max = 0
    any = false
  }
  function finalise (): string {
    flatten(true)
    return (opt ? '^/$|^' : '^') + parts.reduce((acc, seg) => seg + acc, '$')
