      case '**':
        any = true
        break
      default:
        flatten()
        opt = false
        if (part.match(/:.+/) !== null) {
          props.push(part.slice(1))
          parts.push('/([^/]+)')
        } else {
          parts.push(`/${part.replace(/([.$])/g, '\\$1')}`)
